class Solution {
public:
    int minChanges(vector<int>& nums, int k) {
        int changes = 0;
        for (int i = 0; i <= nums.size() - k; ++i) {
            int xor_val = 0;
            for (int j = i; j < i + k; ++j) {
                xor_val ^= nums[j];
            }
            if (xor_val != 0) {
                changes += 1;
            }
        }
        return changes;
    }
};
